  ('diplomatic-0471a791-moex-00503', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-111-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '為了因應中國大陸對我國外交空間的打壓，以及在兩岸關係上步步進逼，蔡總統上任之後即推動「踏 實外交」（SteadfastDiplomacy），下列那一事項是踏實外交的內涵？', '["推動兩岸政治談判", "爭取加入美日同盟", "新南向政策", "推動「蔡習會」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:17+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
