  ('diplomatic-0471a791-moex-00508', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-111-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '英國首相強生（BorisJohnson）在數十位閣員辭職施壓下，2022年7月7日發表聲明，先辭去保守黨黨 魁職務，9月才會辭去首相，並宣布任命新內閣成員，引起黨內外爭議。請問強生為何要9月才辭首相？', '["保守黨要到9月選舉黨魁", "女王慰留", "國會要到9月重新改選", "烏俄戰爭要到9月才會有結果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:17+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00509', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-111-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '日本於2022年7月10日舉行參議院選舉，由自民黨、公明黨、日本維新會、國民民主黨四黨形成的「修 憲勢力」掌握177席，請問此席位數有何特殊意義？', '["自民黨繼續執政，自行提出修憲創議", "超越參議院3/4席次，該勢力可以提出修憲創議", "結合眾議院原掌握的超越2/3席次，共同提出修憲創議", "日本憲法是由當年聯合國駐日盟軍總司令部指導完成，修憲創議需送交聯合國審議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:17+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
